export declare const SIM_VERTEX = "\nvarying vec2 vUv;\nvarying vec2 vL;\nvarying vec2 vR;\nvarying vec2 vT;\nvarying vec2 vB;\nuniform vec2 texelSize;\n\nvoid main() {\n  vUv = position.xy * 0.5 + 0.5;\n  vL = vUv - vec2(texelSize.x, 0.0);\n  vR = vUv + vec2(texelSize.x, 0.0);\n  vT = vUv + vec2(0.0, texelSize.y);\n  vB = vUv - vec2(0.0, texelSize.y);\n  gl_Position = vec4(position.xy, 0.0, 1.0);\n}\n";
export declare const CLEAR_FRAGMENT = "\nprecision mediump float;\nvarying highp vec2 vUv;\nuniform sampler2D uTexture;\nuniform float value;\n\nvoid main() {\n  gl_FragColor = value * texture2D(uTexture, vUv);\n}\n";
export declare const SPLAT_VERTEX = "\nvarying vec2 vLocalUv;\nuniform vec2 uCenter;\nuniform vec2 uScale;\n\nvoid main() {\n  vLocalUv = position.xy;\n  gl_Position = vec4(position.xy * uScale + uCenter, 0.0, 1.0);\n}\n";
export declare const SPLAT_FRAGMENT = "\nprecision highp float;\nvarying vec2 vLocalUv;\nuniform vec3 color;\n\nvoid main() {\n  float r = length(vLocalUv);\n  if (r > 1.0) discard;\n  float a = 1.0 - r;\n  a *= a;\n  gl_FragColor = vec4(color * a, a);\n}\n";
export declare const CURL_FRAGMENT = "\nprecision mediump float;\nvarying highp vec2 vL;\nvarying highp vec2 vR;\nvarying highp vec2 vT;\nvarying highp vec2 vB;\nuniform sampler2D uVelocity;\n\nvoid main() {\n  float L = texture2D(uVelocity, vL).y;\n  float R = texture2D(uVelocity, vR).y;\n  float T = texture2D(uVelocity, vT).x;\n  float B = texture2D(uVelocity, vB).x;\n  float vorticity = R - L - T + B;\n  gl_FragColor = vec4(0.5 * vorticity, 0.0, 0.0, 1.0);\n}\n";
export declare const VORTICITY_FRAGMENT = "\nprecision highp float;\nvarying vec2 vUv;\nvarying vec2 vL;\nvarying vec2 vR;\nvarying vec2 vT;\nvarying vec2 vB;\nuniform sampler2D uVelocity;\nuniform sampler2D uCurl;\nuniform float curl;\nuniform float dt;\n\nvoid main() {\n  float L = texture2D(uCurl, vL).x;\n  float R = texture2D(uCurl, vR).x;\n  float T = texture2D(uCurl, vT).x;\n  float B = texture2D(uCurl, vB).x;\n  float C = texture2D(uCurl, vUv).x;\n  vec2 force = 0.5 * vec2(abs(T) - abs(B), abs(R) - abs(L));\n  force /= length(force) + 0.0001;\n  force *= curl * C;\n  force.y *= -1.0;\n  vec2 vel = texture2D(uVelocity, vUv).xy;\n  gl_FragColor = vec4(vel + force * dt, 0.0, 1.0);\n}\n";
export declare const DIVERGENCE_FRAGMENT = "\nprecision mediump float;\nvarying highp vec2 vUv;\nvarying highp vec2 vL;\nvarying highp vec2 vR;\nvarying highp vec2 vT;\nvarying highp vec2 vB;\nuniform sampler2D uVelocity;\nuniform float uReflectWalls;\n\nvoid main() {\n  float L = texture2D(uVelocity, vL).x;\n  float R = texture2D(uVelocity, vR).x;\n  float T = texture2D(uVelocity, vT).y;\n  float B = texture2D(uVelocity, vB).y;\n  vec2 C = texture2D(uVelocity, vUv).xy;\n  // No-flow-through-walls (reflection): mirror the velocity at boundaries.\n  // Disable to let flow leave the screen \u2014 mofu / FluidCursor behaviour.\n  if (uReflectWalls > 0.5) {\n    if (vL.x < 0.0) { L = -C.x; }\n    if (vR.x > 1.0) { R = -C.x; }\n    if (vT.y > 1.0) { T = -C.y; }\n    if (vB.y < 0.0) { B = -C.y; }\n  }\n  float div = 0.5 * (R - L + T - B);\n  gl_FragColor = vec4(div, 0.0, 0.0, 1.0);\n}\n";
export declare const PRESSURE_FRAGMENT = "\nprecision mediump float;\nvarying highp vec2 vUv;\nvarying highp vec2 vL;\nvarying highp vec2 vR;\nvarying highp vec2 vT;\nvarying highp vec2 vB;\nuniform sampler2D uPressure;\nuniform sampler2D uDivergence;\n\nvoid main() {\n  float L = texture2D(uPressure, vL).x;\n  float R = texture2D(uPressure, vR).x;\n  float T = texture2D(uPressure, vT).x;\n  float B = texture2D(uPressure, vB).x;\n  float divergence = texture2D(uDivergence, vUv).x;\n  float pressure = (L + R + B + T - divergence) * 0.25;\n  gl_FragColor = vec4(pressure, 0.0, 0.0, 1.0);\n}\n";
export declare const GRADIENT_SUBTRACT_FRAGMENT = "\nprecision mediump float;\nvarying highp vec2 vUv;\nvarying highp vec2 vL;\nvarying highp vec2 vR;\nvarying highp vec2 vT;\nvarying highp vec2 vB;\nuniform sampler2D uPressure;\nuniform sampler2D uVelocity;\n\nvoid main() {\n  float L = texture2D(uPressure, vL).x;\n  float R = texture2D(uPressure, vR).x;\n  float T = texture2D(uPressure, vT).x;\n  float B = texture2D(uPressure, vB).x;\n  vec2 velocity = texture2D(uVelocity, vUv).xy;\n  velocity.xy -= vec2(R - L, T - B);\n  gl_FragColor = vec4(velocity, 0.0, 1.0);\n}\n";
export declare const ADVECT_FRAGMENT = "\nprecision highp float;\nvarying vec2 vUv;\nuniform sampler2D uVelocity;\nuniform sampler2D uSource;\nuniform vec2 texelSize;\nuniform float dt;\nuniform float dissipation;\nuniform float uBFECC;\n\nvoid main() {\n  if (uBFECC < 0.5) {\n    vec2 coord = vUv - dt * texture2D(uVelocity, vUv).xy * texelSize;\n    gl_FragColor = dissipation * texture2D(uSource, coord);\n  } else {\n    vec2 vel = texture2D(uVelocity, vUv).xy;\n    vec2 spotOld = vUv - vel * dt * texelSize;\n    vec2 velBack = texture2D(uVelocity, spotOld).xy;\n    vec2 spotForward = spotOld + velBack * dt * texelSize;\n    vec2 error = spotForward - vUv;\n    vec2 spotMid = vUv - error * 0.5;\n    vec2 velMid = texture2D(uVelocity, spotMid).xy;\n    vec2 coord = spotMid - velMid * dt * texelSize;\n    gl_FragColor = dissipation * texture2D(uSource, coord);\n  }\n  gl_FragColor.a = 1.0;\n}\n";
